38: /**
39:  * Hybrid source that switches underlying sources based on configured source chain.
40:  *
41:  * <p>A simple example with FileSource and KafkaSource with fixed Kafka start position:
42:  *
43:  * <pre>{@code
44:  * FileSource<String> fileSource =
45:  *   FileSource.forRecordStreamFormat(new TextLineInputFormat(), Path.fromLocalFile(testDir)).build();
46:  * KafkaSource<String> kafkaSource =
47:  *           KafkaSource.<String>builder()
48:  *                   .setBootstrapServers("localhost:9092")
49:  *                   .setGroupId("MyGroup")
50:  *                   .setTopics(Arrays.asList("quickstart-events"))
51:  *                   .setDeserializer(
52:  *                           KafkaRecordDeserializer.valueOnly(StringDeserializer.class))
53:  *                   .setStartingOffsets(OffsetsInitializer.earliest())
54:  *                   .build();
55:  * HybridSource<String> hybridSource =
56:  *           HybridSource.builder(fileSource)
57:  *                   .addSource(kafkaSource)
58:  *                   .build();
59:  * }</pre>
60:  *
61:  * <p>A more complex example with Kafka start position derived from previous source:
62:  *
63:  * <pre>{@code
64:  * HybridSource<String> hybridSource =
65:  *     HybridSource.<String, StaticFileSplitEnumerator>builder(fileSource)
66:  *         .addSource(
67:  *             switchContext -> {
68:  *               StaticFileSplitEnumerator previousEnumerator =
69:  *                   switchContext.getPreviousEnumerator();
70:  *               // how to get timestamp depends on specific enumerator
71:  *               long timestamp = previousEnumerator.getEndTimestamp();
72:  *               OffsetsInitializer offsets =
73:  *                   OffsetsInitializer.timestamp(timestamp);
74:  *               KafkaSource<String> kafkaSource =
75:  *                   KafkaSource.<String>builder()
76:  *                       .setBootstrapServers("localhost:9092")
77:  *                       .setGroupId("MyGroup")
78:  *                       .setTopics(Arrays.asList("quickstart-events"))
79:  *                       .setDeserializer(
80:  *                           KafkaRecordDeserializer.valueOnly(StringDeserializer.class))
81:  *                       .setStartingOffsets(offsets)
82:  *                       .build();
83:  *               return kafkaSource;
84:  *             },
85:  *             Boundedness.CONTINUOUS_UNBOUNDED)
86:  *         .build();
87:  * }</pre>
88:  */
